import classes from './Poster.module.css';


const Poster=()=>{
    return <div id="poster">

<div className={classes.main}>
<div className={`${classes.overlay} ${classes.overlayFade}`}>
    <div className={classes.text}>SACHINE TOOL ENGINEERING</div>
            </div>

</div>



</div>



};


export default Poster;
